const Web3 = require('web3');
const web3 = new Web3(new Web3.providers.HttpProvider('https://mainnet.infura.io/v3/YOUR_API_KEY'));

// Wallet configuration with private keys for signing transactions
const wallet = web3.eth.accounts.privateKeyToAccount('0xPRIVATE_KEY');

// Function to send ETH
async function sendETH(recipient, amount) {
  const tx = {
    from: wallet.address,
    to: recipient,
    value: web3.utils.toWei(amount),
  };
  await web3.eth.sendTransaction(tx);
}

// Function to interact with a smart contract
async function interactWithContract(contractAddress, abi, functionName, args) {
  const contract = new web3.eth.Contract(abi, contractAddress);
  const result = await contract[functionName](...args);
  return result;
}

// Example usage of the functions
